import { NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/app/lib/auth"; 
import {prisma} from "@/app/lib/prisma"; // ใช้ @ ป้องกันปัญหา Path

export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);

    // 1. ตรวจสอบว่าคนที่ส่งคำสั่งมา เป็น ADMIN จริงๆ หรือไม่
    if (!session || (session.user as any).role !== "ADMIN") {
      return NextResponse.json({ error: "Unauthorized: ไม่ได้รับสิทธิ์" }, { status: 401 });
    }

    // 2. รับค่า ID และ Role ใหม่ที่แอดมินเลือก
    const { userId, newRole } = await req.json();

    if (!userId || !newRole) {
      return NextResponse.json({ error: "ข้อมูลไม่ครบถ้วน" }, { status: 400 });
    }

    // 3. สั่งอัปเดตฐานข้อมูล
    await prisma.user.update({
      where: { id: userId },
      data: { role: newRole }
    });

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error("Role Update Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}